sys_script_include.script:
var IncentNowDecisionCRUD= Class.create();
IncentNowDecisionCRUD.prototype = {

    initialize: function() {},

    // =====================================
    // SAVE FULL LOOKUP CONFIGURATION
    // =====================================
    saveFullLookup: function(sysId, columns, rows) {

        try {

            if (!sysId) {
                return { status: "error", message: "Invalid sysId" };
            }

            // ================= CLEAN OLD =================
            var oldRes = new GlideRecordSecure('sys_decision_multi_result');
            oldRes.addQuery('decision_table', sysId);
            oldRes.query();
            while (oldRes.next()) oldRes.deleteRecord();

            var oldInput = new GlideRecordSecure('sys_decision_input');
            oldInput.addQuery('model_id', sysId);
            oldInput.query();
            while (oldInput.next()) oldInput.deleteRecord();

            var oldQ = new GlideRecordSecure('sys_decision_question');
            oldQ.addQuery('decision_table', sysId);
            oldQ.query();
            while (oldQ.next()) oldQ.deleteRecord();

            var oldOut = new GlideRecordSecure('sys_decision_multi_result_element');
            oldOut.addQuery('model_id', sysId);
            oldOut.query();
            while (oldOut.next()) oldOut.deleteRecord();

            // ================= CREATE INPUTS =================
            var inputMap = {};
            var outputMap = {};

            for (var i = 0; i < columns.length; i++) {

                var col = columns[i];

                if (col.type === 'input') {

                    var inp = new GlideRecordSecure('sys_decision_input');
                    inp.initialize();
                    inp.setValue('model_id', sysId);
                    inp.setValue('name', col.sys_id);
                    inp.setValue('label', col.name);
                    inp.setValue('order', i);
                    var inpId = inp.insert();

                    inputMap[col.sys_id] = col.sys_id;
                }

                if (col.type === 'output') {

                    var out = new GlideRecordSecure('sys_decision_multi_result_element');
                    out.initialize();
                    out.setValue('model_id', sysId);
                    out.setValue('label', col.name);
                    out.setValue('order', i);
                    var outId = out.insert();

                    outputMap[col.sys_id] = outId;
                }
            }

            // ================= CREATE ROWS =================
            for (var r = 0; r < rows.length; r++) {

                var row = rows[r];

                var res = new GlideRecordSecure('sys_decision_multi_result');
                res.initialize();
                res.setValue('decision_table', sysId);
                var resId = res.insert();

                for (var key in row.values) {

                    var value = row.values[key];

                    // VALUES
                    var val = new GlideRecordSecure('sys_variable_value');
                    val.initialize();
                    val.setValue('document_key', resId);
                    val.setValue('variable', key);
                    val.setValue('value', value);
                    val.insert();

                    // CONDITIONS (ONLY FOR INPUTS)
                    if (inputMap[key]) {

                        var q = new GlideRecordSecure('sys_decision_question');
                        q.initialize();
                        q.setValue('decision_table', sysId);
                        q.setValue('answer', resId);
                        q.setValue('condition', key + "=" + value);
                        q.insert();
                    }
                }
            }

            return {
                status: "success",
                message: "Lookup saved successfully"
            };

        } catch (e) {

            gs.error("FULL SAVE ERROR: " + e.message);

            return {
                status: "error",
                message: e.message
            };
        }
    },

    type: 'IncentNowDecisionCRUD'
};
